import * as jose from "jose";
import { v4 as uuidv4 } from "uuid";
import { getPool } from "../db/pool.js";

const ALG = () => process.env.SIGNING_ALGORITHM || "ES256";

/**
 * Generate a new ES256 key pair and persist to DB.
 * Returns the kid.
 */
export async function generateKeyPair() {
  const alg = ALG();
  const { publicKey, privateKey } = await jose.generateKeyPair(alg, { extractable: true });

  const publicJwk = await jose.exportJWK(publicKey);
  const privateJwk = await jose.exportJWK(privateKey);

  const kid = `${process.env.ISSUER_ID || "https://portauth-issuer.local"}/${uuidv4().slice(0, 8)}`;
  publicJwk.kid = kid;
  publicJwk.alg = alg;
  publicJwk.use = "sig";
  privateJwk.kid = kid;
  privateJwk.alg = alg;

  const pool = getPool();
  await pool.query(
    `INSERT INTO portauth_signing_keys (kid, algorithm, public_jwk, private_jwk)
     VALUES ($1, $2, $3, $4)`,
    [kid, alg, JSON.stringify(publicJwk), JSON.stringify(privateJwk)]
  );

  return kid;
}

/**
 * Get the active signing key (most recently created active key).
 * Returns { kid, privateKey, publicJwk }.
 */
export async function getActiveSigningKey() {
  const pool = getPool();
  const { rows } = await pool.query(
    `SELECT kid, algorithm, public_jwk, private_jwk
     FROM portauth_signing_keys
     WHERE active = TRUE
     ORDER BY created_at DESC
     LIMIT 1`
  );

  if (rows.length === 0) {
    // Auto-generate on first use
    const kid = await generateKeyPair();
    return getActiveSigningKey();
  }

  const row = rows[0];
  const privateKey = await jose.importJWK(row.private_jwk, row.algorithm);
  return {
    kid: row.kid,
    algorithm: row.algorithm,
    privateKey,
    publicJwk: row.public_jwk,
  };
}

/**
 * Get all public keys (for JWKS endpoint).
 */
export async function getPublicKeys() {
  const pool = getPool();
  const { rows } = await pool.query(
    `SELECT public_jwk FROM portauth_signing_keys ORDER BY created_at DESC`
  );
  return rows.map(r => r.public_jwk);
}

/**
 * Rotate: deactivate all current keys and generate a new one.
 */
export async function rotateKeys() {
  const pool = getPool();
  await pool.query(
    `UPDATE portauth_signing_keys SET active = FALSE, rotated_at = NOW() WHERE active = TRUE`
  );
  return generateKeyPair();
}
